const body = $input.first().json.body;

const required = ['customer_id', 'trigger_type'];
const missing = required.filter(f => !body[f]);
if (missing.length > 0) {
  throw new Error(`Missing fields: ${missing.join(', ')}`);
}

const validTriggers = [
  'renewal', 'lifecycle_event', 'segment_campaign',
  'cross_sell_signal', 'upsell_signal', 'retention_linked'
];

if (!validTriggers.includes(body.trigger_type)) {
  throw new Error(`Unknown trigger_type: ${body.trigger_type}`);
}

return [{
  json: {
    offer_trigger_id: body.offer_trigger_id || `OT-${Date.now()}`,
    customer_id: body.customer_id,
    trigger_type: body.trigger_type,
    triggered_at: new Date().toISOString(),
    pipeline: 'offer',
    // Pass-through optional fields
    offer_type_hint: body.offer_type_hint || null,
    source_pipeline: body.source_pipeline || 'direct'
  }
}];

// Inputs from upstream nodes:
//   [0] = Trigger: Offer Event  (original webhook payload)
//   [1] = Load Customer Profile (stub response)
//   [2] = Load Product Catalogue
//   [3] = Load Recent Offers

const trigger     = $('Validate & Init Offer').first().json;
const profile     = $('Load Customer Profile').first().json;
const products    = $('Load Product Catalogue').first().json;
const recentOffers = $('Load Recent Offers').first().json;

const enriched = {
  offer_trigger_id: trigger.offer_trigger_id,
  customer_id:      trigger.customer_id,
  trigger_type:     trigger.trigger_type,

  // Customer (from profile stub)
  customer_name:        profile.customer_name        || null,
  segment:              profile.segment              || null,
  age_group:            profile.age_group            || null,
  customer_since_years: profile.customer_since_years || null,
  annual_premium:       profile.annual_premium       || null,
  customer_ltv:         profile.customer_ltv         || null,

  // Coverage
  existing_products:    profile.existing_products    || [],

  // Life events & business context
  recent_life_events:   profile.recent_life_events   || [],
  industry:             profile.industry             || null,
  employee_count:       profile.employee_count       || null,
  annual_revenue:       profile.annual_revenue       || null,

  // Offer history
  offers_sent_last_90_days: recentOffers.offers_sent || [],

  // Available products (from catalogue, fallback to default)
  available_products: products.available || [
    'hausrat', 'haftpflicht_privat', 'life_insurance', 'unfall',
    'rechtsschutz_privat', 'cyber_privat', 'cyber_business',
    'kfz_haftpflicht', 'vollkasko', 'reise', 'krankentaggeld',
    'gebaeude', 'betrieb'
  ]
};

return [{ json: enriched }];

// Orchestrator: business rule validation for offers
const agent = $json;

let finalRoute = agent.recommended_route;
let overrideReason = null;

// Rule 1: High-value offers (> CHF 5000/year estimated) always need sales handoff
const premiumStr = agent.estimated_annual_premium || '';
const premiumMax = parseFloat(premiumStr.replace(/[^0-9.]/g, '').split(' ').pop()) || 0;
if (premiumMax > 5000 && finalRoute === 'automated_offer') {
  finalRoute = 'sales_handoff';
  overrideReason = `Estimated premium > CHF 5000 — escalated to sales`;
}

// Rule 2: Low cross-sell score despite automated route
if (agent.cross_sell_score < 0.50 && finalRoute === 'automated_offer') {
  finalRoute = 'nurturing_sequence';
  overrideReason = `Cross-sell score too low for direct offer (${agent.cross_sell_score.toFixed(2)})` ;
}

// Rule 3: Duplicate prevention — product already in recent offers
const recentOffers = $('Build Offer Context').first().json.offers_sent_last_90_days || [];
if (recentOffers.includes(agent.recommended_product) && finalRoute === 'automated_offer') {
  finalRoute = 'nurturing_sequence';
  overrideReason = `${agent.recommended_product} already offered in last 90 days — moved to nurturing`;
}

return [{
  json: {
    ...agent,
    final_route: finalRoute,
    orchestrator_override: finalRoute !== agent.recommended_route,
    override_reason: overrideReason,
    orchestrated_at: new Date().toISOString()
  }
}];

// AUTOMATED OFFER: Generate & send personalized offer via email/portal
const data = $json;
return [{
  json: {
    action: 'automated_offer',
    offer_trigger_id: data.offer_trigger_id,
    customer_id: data.customer_id,
    product: data.recommended_product,
    product_display_name: data.product_display_name,
    personalization_angle: data.personalization_angle,
    estimated_premium: data.estimated_annual_premium,
    channel: data.channel_recommendation,
    urgency: data.urgency,
    cross_sell_score: data.cross_sell_score,
    message: `Automated offer: ${data.product_display_name} → ${data.customer_id}`,
    created_at: new Date().toISOString()
  }
}];

// SALES HANDOFF: Create lead/task in sales CRM
const data = $json;
return [{
  json: {
    action: 'sales_handoff',
    offer_trigger_id: data.offer_trigger_id,
    customer_id: data.customer_id,
    product: data.recommended_product,
    product_display_name: data.product_display_name,
    estimated_premium: data.estimated_annual_premium,
    personalization_angle: data.personalization_angle,
    cross_sell_score: data.cross_sell_score,
    reasoning: data.reasoning,
    flags: data.flags,
    assign_to: 'sales_team',
    priority: data.urgency === 'high' ? 'HIGH' : 'MEDIUM',
    message: `Sales task: ${data.product_display_name} for ${data.customer_id}`,
    created_at: new Date().toISOString()
  }
}];

// NURTURING: Add to email nurturing sequence
const data = $json;
return [{
  json: {
    action: 'nurturing_sequence',
    offer_trigger_id: data.offer_trigger_id,
    customer_id: data.customer_id,
    product: data.recommended_product,
    personalization_angle: data.personalization_angle,
    sequence_name: `nurture_${data.recommended_product}`,
    cross_sell_score: data.cross_sell_score,
    override_reason: data.override_reason,
    message: `Nurturing sequence started: ${data.recommended_product} for ${data.customer_id}`,
    created_at: new Date().toISOString()
  }
}];
